section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/voice-ui-patterns.json",
  "title": "Voice UI Patterns",
  "type": "object",
  "required": [
    "artefact_id",
    "skill_id",
    "intent_map",
    "prompt_rules",
    "error_ladder_ref",
    "multimodal_policy",
    "platform_targets",
    "kpis",
    "owner",
    "evidence",
    "status",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "skill_id": {
      "type": "string",
      "description": "skill_id",
      "minLength": 1
    },
    "intent_map": {
      "type": "string",
      "description": "intent_map",
      "minLength": 1
    },
    "prompt_rules": {
      "type": "array",
      "description": "prompt_rules (array)",
      "minItems": 1
    },
    "error_ladder_ref": {
      "type": "string",
      "description": "error_ladder_ref",
      "minLength": 1
    },
    "multimodal_policy": {
      "type": "string",
      "description": "multimodal_policy",
      "minLength": 1
    },
    "platform_targets": {
      "type": "array",
      "description": "platform_targets (array)",
      "minItems": 1
    },
    "kpis": {
      "type": "array",
      "description": "kpis (array)",
      "minItems": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation} pairs anchoring non-trivial fields",
      "minItems": 1
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    }
  },
  "additionalProperties": false
}
